selector_to_html = {"a[href=\"#interpretacion\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Interpretaci\u00f3n<a class=\"headerlink\" href=\"#interpretacion\" title=\"Link to this heading\">#</a></h2><p>La derivada conformable <strong>reescala el eje temporal</strong> por un factor <span class=\"math notranslate nohighlight\">\\(t^{\\,1-\\alpha}\\)</span>:</p>", "a[href=\"#interpretacion-fisica\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Interpretaci\u00f3n F\u00edsica<a class=\"headerlink\" href=\"#interpretacion-fisica\" title=\"Link to this heading\">#</a></h3><p>El factor de escalamiento dependiente del tiempo <span class=\"math notranslate nohighlight\">\\(t^{\\alpha-1}\\)</span> tiene implicaciones f\u00edsicas interesantes:</p>", "a[href=\"#sistema-i-pendulo-fraccionario-conformable\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema I: P\u00e9ndulo Fraccionario Conformable<a class=\"headerlink\" href=\"#sistema-i-pendulo-fraccionario-conformable\" title=\"Link to this heading\">#</a></h2><h3>Derivaci\u00f3n Paso a Paso<a class=\"headerlink\" href=\"#derivacion-paso-a-paso\" title=\"Link to this heading\">#</a></h3><p>Para establecer una l\u00ednea base, primero se define el sistema cl\u00e1sico del p\u00e9ndulo no lineal con amortiguamiento. Las ecuaciones gobernantes son:</p><p><strong>Sistema Cl\u00e1sico Original del P\u00e9ndulo:</strong>\n$<span class=\"math notranslate nohighlight\">\\(\n\\begin{aligned}\nx_1' &amp;= x_2 \\\\\nx_2' &amp;= -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2\n\\end{aligned}\n\\)</span>$</p>", "a[href=\"#nota-importante-sobre-las-condiciones-iniciales\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Nota Importante Sobre las Condiciones Iniciales<a class=\"headerlink\" href=\"#nota-importante-sobre-las-condiciones-iniciales\" title=\"Link to this heading\">#</a></h3><p>Cabe recordar que la definici\u00f3n de la derivada conformable requiere que <span class=\"math notranslate nohighlight\">\\(t &gt; 0\\)</span>. Para las simulaciones num\u00e9ricas, ser\u00e1 necesario comenzar en alg\u00fan <span class=\"math notranslate nohighlight\">\\(t_0 &gt; 0\\)</span> (e.g., <span class=\"math notranslate nohighlight\">\\(t_0 = 0.1\\)</span> o <span class=\"math notranslate nohighlight\">\\(t_0 = 1\\)</span>) para evitar la singularidad en <span class=\"math notranslate nohighlight\">\\(t = 0\\)</span> cuando <span class=\"math notranslate nohighlight\">\\(\\alpha &lt; 1\\)</span>.</p>", "a[href=\"#derivacion-paso-a-paso\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Derivaci\u00f3n Paso a Paso<a class=\"headerlink\" href=\"#derivacion-paso-a-paso\" title=\"Link to this heading\">#</a></h3><p>Para establecer una l\u00ednea base, primero se define el sistema cl\u00e1sico del p\u00e9ndulo no lineal con amortiguamiento. Las ecuaciones gobernantes son:</p><p><strong>Sistema Cl\u00e1sico Original del P\u00e9ndulo:</strong>\n$<span class=\"math notranslate nohighlight\">\\(\n\\begin{aligned}\nx_1' &amp;= x_2 \\\\\nx_2' &amp;= -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2\n\\end{aligned}\n\\)</span>$</p>", "a[href=\"#consistencia-dimensional-sigma\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Consistencia Dimensional (<span class=\"math notranslate nohighlight\">\\(\\sigma\\)</span>)<a class=\"headerlink\" href=\"#consistencia-dimensional-sigma\" title=\"Link to this heading\">#</a></h2><p>En los sistemas f\u00edsicos, cambiar el orden de la derivada de <span class=\"math notranslate nohighlight\">\\(1\\)</span> a <span class=\"math notranslate nohighlight\">\\(\\alpha\\)</span> altera las unidades fundamentales de la ecuaci\u00f3n (e.g., de <span class=\"math notranslate nohighlight\">\\(s^{-1}\\)</span> a <span class=\"math notranslate nohighlight\">\\(s^{-\\alpha}\\)</span>). Para preservar la homogeneidad dimensional y el significado f\u00edsico, se introduce un par\u00e1metro de escalamiento <span class=\"math notranslate nohighlight\">\\(\\sigma\\)</span> con unidades de tiempo <span class=\"math notranslate nohighlight\">\\([s]\\)</span>. La formulaci\u00f3n dimensionalmente robusta resulta ser:</p>", "a[href=\"#propiedades-principales\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Propiedades Principales<a class=\"headerlink\" href=\"#propiedades-principales\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#derivada-conformable-de-khalil\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Derivada conformable de Khalil<a class=\"headerlink\" href=\"#derivada-conformable-de-khalil\" title=\"Link to this heading\">#</a></h1><p>La derivada conformable de orden <span class=\"math notranslate nohighlight\">\\(\\alpha \\in (0,1]\\)</span> fue introducida por <span id=\"id1\">(<a class=\"reference internal\" href=\"../references.html#id2\" title=\"Khalil, R., Al Horani, M., Yousef, A., &amp; Sababheh, M. (2014). A new definition of fractional derivative. Journal of computational and applied mathematics, 264, 65\u201370.\">Khalil <em>et al.</em>, 2014</a>)</span> como una generalizaci\u00f3n simple, local y altamente eficiente de la derivada cl\u00e1sica.</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(`article.bd-article ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: false,
                placement: 'auto-start', maxWidth: 500, interactive: true, boundary: document.body, appendTo: document.body,
                onShow(instance) {MathJax.typesetPromise([instance.popper]).then(() => {var isFirefox=typeof InstallTrigger!=='undefined';if(isFirefox&&window.MathJax&&MathJax.startup&&MathJax.startup.output&&MathJax.startup.output.name==="SVG"){const svgs=instance.popper.querySelectorAll('svg');svgs.forEach(svg=>{let bbox=svg.getBBox(),x=bbox.x,y=bbox.y,width=bbox.width,height=bbox.height;svg.setAttribute('width',width);svg.setAttribute('height',height);svg.setAttribute('viewBox',`${x} ${y} ${width} ${height}`);});let rescale=0.015;svgs.forEach(svg=>{let bbox=svg.getBBox(),width=bbox.width,height=bbox.height;svg.setAttribute('width',width*rescale);svg.setAttribute('height',height*rescale);});}});},
            });
        };
    };
    console.log("tippy tips loaded!");
};
